INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '01fd32b2-f1be-42df-87b9-cf265e1c0e4f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Playwright — Test Behaviour Not Implementation: Query by Role, Not by Class$escape$,
  $escape$Playwright's Locator API encourages behaviour-driven selectors that survive refactors. When you query by CSS class or test ID, you're coupling tests to implementation details — a designer renaming `.btn-primary` breaks your suite without breaking the app.

Instead, reach for `getByRole()`, `getByLabel()`, `getByText()`, and `getByPlaceholder()`. These mirror how real users perceive the UI, and how assistive technologies traverse it. A button is a button because of its ARIA role, not its class name.

`getByRole('button', { name: 'Submit' })` finds exactly the element a screen reader would announce as "Submit button" — regardless of whether the underlying element is a `<button>`, `<input type="submit">`, or a custom component with `role="button"`.

This philosophy also improves accessibility coverage for free: if `getByRole` can't find it, neither can a screen reader. Pair it with `toBeVisible()` and `toBeEnabled()` assertions to verify observable behaviour, not DOM structure. Reserve `data-testid` only when no semantic query is possible.$escape$,
  $escape$import { test, expect } from '@playwright/test';

test('user submits contact form', async ({ page }) => {
  await page.goto('/contact');

  // Query by label — survives HTML restructuring
  await page.getByLabel('Email address').fill('dev@example.com');
  await page.getByLabel('Message').fill('Hello from Playwright');

  // Query by role + accessible name — not by class or selector
  await page.getByRole('button', { name: 'Send message' }).click();

  // Assert observable outcome, not DOM mutation
  await expect(page.getByRole('alert')).toHaveText('Message sent!');
});$escape$,
