INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '74691f5f-ffa0-4d4f-9bf7-142c3b452c21',
  '00000000-0000-0000-0000-000000000001',
  $escape$Playwright Component Testing — Render, Interact, Assert Without a Full Browser App$escape$,
  $escape$Playwright's experimental `@playwright/experimental-ct-react` (or Vue/Svelte variants) lets you mount individual components in isolation — no dev server, no routing, no full app shell. You call `mount()` from `@playwright/experimental-ct-react`, pass props directly, and get back a `Locator`-compatible handle. From there, every standard Playwright API works exactly as in E2E tests: `click()`, `fill()`, `expect(component).toHaveText()`, `toBeVisible()`, `toHaveAttribute()`.

The key difference from E2E: you control props and slots at the test boundary, so you never need to navigate or seed a database to exercise a component's visual states. Use `component.update({ props })` to re-render with new props mid-test and assert on the resulting DOM without a page reload. For interaction testing, Playwright's actionability checks (auto-wait for visible + enabled) still apply — `click()` won't fire on a disabled button, keeping your assertions honest. Slot/children injection works too, letting you test compound components like `<Dialog>` without mocking a trigger.$escape$,
  $escape$import { test, expect } from '@playwright/experimental-ct-react';
import { StatusBadge } from './StatusBadge';

test('shows error styling when status is failed', async ({ mount }) => {
  const component = await mount(<StatusBadge status="failed" label="Build" />);

  await expect(component).toHaveText('Build');
  await expect(component).toHaveAttribute('data-status', 'failed');
  await expect(component.getByRole('img', { name: /error/i })).toBeVisible();

  await component.update({ props: { status: 'success', label: 'Build' } });
  await expect(component).toHaveAttribute('data-status', 'success');
});$escape$,
