INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '02a0cfc0-ce61-43ed-b9fe-6e217faf03da',
  '00000000-0000-0000-0000-000000000001',
  $escape$Playwright Component Testing — Testing Custom Hooks Without renderHook$escape$,
  $escape$Playwright's `@playwright/experimental-ct-react` ships no `renderHook` utility. Instead, build a minimal HookHarness component that exposes your hook's return values through testable DOM nodes, then mount it with Playwright's `mount()`. This runs inside a real Chromium, Firefox, or WebKit process — not jsdom — which catches browser-specific edge cases that RTL misses entirely.

For pure functions with no browser dependencies, call them directly in the test body; no mounting overhead required. For functions that touch browser APIs — `localStorage`, `matchMedia`, `ResizeObserver`, `requestAnimationFrame` — use `page.evaluate()` to execute them in browser context with full native API access.

The critical difference from RTL's `renderHook` is environment fidelity. A hook wrapping `IntersectionObserver` or `Web Workers` fires against real browser internals, not stubs. jsdom's `IntersectionObserver` mock diverges from Chrome's threshold logic; Playwright doesn't lie. The tradeoff is speed — Playwright component tests run 5–10× slower than Jest. Reserve them for hooks with genuine browser dependencies; use Vitest for the rest.$escape$,
  $escape$// CounterHarness.tsx
function CounterHarness() {
  const { count, increment } = useCounter();
  return <button data-testid="count" onClick={increment}>{count}</button>;
}

// useCounter.spec.tsx
import { test, expect } from '@playwright/experimental-ct-react';
import { CounterHarness } from './CounterHarness';

test('useCounter increments on click', async ({ mount }) => {
  const component = await mount(<CounterHarness />);
  await component.getByTestId('count').click();
  await expect(component.getByTestId('count')).toHaveText('1');
});$escape$,
  $escape$typescript$escape$,
