INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd905606c-eb60-47ec-8b2f-23f8b83fa4fe',
  '00000000-0000-0000-0000-000000000001',
  $escape$Playwright Integration Testing — Mocking at the Right Boundary$escape$,
  $escape$Integration tests in Playwright verify that multiple components work together — a form submission that triggers an API call and updates the UI. The key decision is where to mock. Mock too low (individual functions) and you're unit testing. Mock too high (the entire backend) and you miss real integration failures.

The right boundary is the network layer. Use `page.route()` to intercept HTTP requests at the fetch/XHR level, letting your actual React components, state management, and DOM interactions run unmodified. This validates the full frontend slice — component rendering, event handlers, state updates — while keeping tests deterministic.

For component composition tests, avoid `page.evaluate()` stubs. Instead, seed the network mock with realistic response shapes matching your actual API contract. If you use MSW in development, reuse those same handlers via `playwright-msw` to keep mocks DRY across test environments.

Use `page.waitForResponse()` to assert the correct request was made before checking UI state — this avoids brittle `waitForTimeout()` calls and explicitly documents the async dependency.$escape$,
  $escape$import { test, expect } from '@playwright/test';

test('submit creates post and shows confirmation', async ({ page }) => {
  await page.route('**/api/posts', async route => {
    expect(route.request().method()).toBe('POST');
    const body = route.request().postDataJSON();
    expect(body.title).toBeTruthy();
    await route.fulfill({
      status: 201,
      json: { id: 'abc123', title: body.title }
    });
  });

  await page.goto('/create');
  await page.getByLabel('Title').fill('Playwright rocks');
  await page.getByRole('button', { name: 'Publish' }).click();

  const response = await page.waitForResponse('**/api/posts');
  expect(response.status()).toBe(201);
  await expect(page.getByText('Post published!')).toBeVisible();
});$escape$,
