INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '96d7571b-2413-4d25-b1bf-ce7ce022bc93',
  '00000000-0000-0000-0000-000000000001',
  $escape$Playwright E2E — Testing Critical Paths Without Drowning in Flake$escape$,
  $escape$E2E tests are expensive — run them selectively on paths that break users, not every UI interaction. In Playwright, structure critical flows as isolated, stateless tests using `storageState` to bypass auth on every run. Authenticate once in a `globalSetup`, serialize the session to a JSON file, and load it per-test via `use.storageState` in `playwright.config.ts`. This eliminates the login flow from every test while still covering it in a dedicated auth spec.

For onboarding and core feature flows, use `page.getByRole()` and `page.getByLabel()` over CSS selectors — they survive UI refactors and mirror how users interact with the page. Chain `expect(page).toHaveURL()` at route transitions to assert navigation without arbitrary waits.

Scope each test to one critical path. Auth spec owns login/logout/session-expiry. Onboarding spec owns the setup wizard end-to-end. Core feature spec owns the primary happy path. Tag them with `@critical` and run only these in CI pre-merge; full suite runs nightly. This keeps your pipeline fast and your signal high.$escape$,
  $escape$// playwright.config.ts
import { defineConfig } from '@playwright/test';

export default defineConfig({
  use: {
    storageState: 'e2e/.auth/user.json',
  },
  projects: [
    {
      name: 'setup',
      testMatch: '**/auth.setup.ts',
    },
    {
      name: 'critical',
      grep: /@critical/,
      dependencies: ['setup'],
    },
  ],
});

// e2e/auth.setup.ts
import { test as setup } from '@playwright/test';

setup('authenticate', async ({ page }) => {
  await page.goto('/login');
  await page.getByLabel('Email').fill(process.env.TEST_EMAIL!);
  await page.getByLabel('Password').fill(process.env.TEST_PASSWORD!);
  await page.getByRole('button', { name: 'Sign in' }).click();
  await page.waitForURL('/dashboard');
  await page.context().storageState({ path: 'e2e/.auth/user.json' });
});$escape$,
  $escape$typescript$escape$,
