INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e7a99586-bade-4769-90dc-c3754c49c2cd',
  '00000000-0000-0000-0000-000000000001',
  $escape$Playwright Async Testing — waitFor, Auto-Waiting, and Taming Fake Timers$escape$,
  $escape$Playwright's auto-waiting bakes assertions directly into locator actions — `locator.click()` waits for the element to be visible, stable, and enabled before acting. But for custom conditions, `page.waitForFunction()` lets you poll arbitrary JS: `await page.waitForFunction(() => window.__dataLoaded === true)`. For network-driven UI updates, `page.waitForResponse()` or `page.waitForRequest()` give you precise control without arbitrary timeouts.

Locator assertions via `expect(locator).toBeVisible()` retry internally up to the configured `timeout` — no manual polling needed. Avoid `page.waitForTimeout()` entirely; it's a code smell that masks real flakiness.

Fake timers are where Playwright diverges sharply from Jest. You install them via `page.clock.install()` (Playwright 1.45+), then advance with `page.clock.fastForward(5000)` or `page.clock.runFor(3000)`. This controls `setTimeout`, `setInterval`, and `Date` inside the browser context — not the Node test runner. Combine with `expect(locator).toHaveText()` after advancing the clock to assert debounced UI updates deterministically.$escape$,
  $escape$import { test, expect } from '@playwright/test';

test('debounced search updates after 500ms', async ({ page }) => {
  await page.clock.install();
  await page.goto('/search');

  await page.getByRole('searchbox').fill('playwright');

  // Debounce hasn't fired yet — results still empty
  await expect(page.getByTestId('results')).toBeEmpty();

  // Advance clock past debounce threshold
  await page.clock.fastForward(500);

  await expect(page.getByTestId('results')).not.toBeEmpty();

  // Assert specific network call was made
  await page.waitForResponse(resp =>
    resp.url().includes('/api/search') && resp.status() === 200
  );
});$escape$,
