INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '23b19fd0-5615-4058-95a1-792929640fe3',
  '00000000-0000-0000-0000-000000000001',
  $escape$Playwright Visual Regression — toHaveScreenshot, Chromatic, and CI Diffing$escape$,
  $escape$Playwright's built-in visual regression uses `expect(page).toHaveScreenshot()`, which stores `.png` baselines under `__snapshots__` and pixel-diffs on every subsequent run. Tune sensitivity with `{ maxDiffPixels: 50 }` or `{ threshold: 0.2 }` (ratio of differing pixels) — tighter thresholds catch sub-pixel regressions, looser ones survive anti-aliasing noise across OS renderers.

For component-level coverage, `@chromatic-com/playwright` ships a `takeSnapshot` helper that pipes Playwright screenshots into Chromatic's cloud diffing engine, giving you a PR-gated UI review workflow without managing baseline files in git.

In CI, never commit stale baselines. Instead, gate on `--update-snapshots` only on a dedicated baseline branch, then treat snapshot mismatches as hard failures on feature branches. Use `snapshotPathTemplate` in `playwright.config.ts` to namespace baselines by OS and browser (`{testFileDir}/__snapshots__/{platform}/{browserName}/{arg}{ext}`), preventing Linux CI from invalidating macOS baselines and vice versa. Combine Playwright's native diffing for full-page flows with Chromatic for isolated Storybook components — they solve different granularities of the same problem.$escape$,
  $escape$// playwright.config.ts
import { defineConfig } from '@playwright/test';

export default defineConfig({
  snapshotPathTemplate:
    '{testFileDir}/__snapshots__/{platform}/{browserName}/{arg}{ext}',
  expect: {
    toHaveScreenshot: { maxDiffPixels: 50, animations: 'disabled' },
  },
});

// homepage.spec.ts
test('hero section visual baseline', async ({ page }) => {
  await page.goto('/');
  await page.locator('[data-testid="hero"]').waitFor({ state: 'visible' });
  await expect(page).toHaveScreenshot('hero.png', { fullPage: false });
});$escape$,
  $escape$typescript$escape$,
