INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'dab0a9df-46ab-4e77-a5a0-27fbb4cd4248',
  '00000000-0000-0000-0000-000000000001',
  $escape$Playwright + axe-core — Automated Accessibility Audits in Every Test$escape$,
  $escape$Playwright has no built-in a11y engine, but `@axe-core/playwright` plugs directly into any test via the `AxeBuilder` class. After navigating to a page, construct an `AxeBuilder` with the current `page`, call `.analyze()`, and assert against `results.violations`. Each violation carries `id`, `impact`, `nodes`, and `helpUrl` — enough context to fix the issue without leaving the terminal.

Scope audits with `.include('#main-content')` to skip third-party widgets you can't control, or `.exclude('.legacy-widget')` to suppress known noise. Use `.withTags(['wcag2a', 'wcag2aa'])` to target a specific conformance level rather than running every axe rule on every page load — this cuts runtime and keeps CI failures actionable.

Pair this with Playwright's `--reporter=html` so violations are surfaced inline alongside screenshots and traces. For component-level coverage, run the same `AxeBuilder` pattern inside `@playwright/experimental-ct-react` tests to catch a11y regressions before they reach a full page.$escape$,
  $escape$import { test, expect } from '@playwright/test';
import AxeBuilder from '@axe-core/playwright';

test('homepage passes WCAG 2.1 AA', async ({ page }) => {
  await page.goto('/');

  const results = await new AxeBuilder({ page })
    .withTags(['wcag2a', 'wcag2aa'])
    .exclude('.third-party-chat-widget')
    .analyze();

  expect(results.violations).toEqual([]);
});

test('modal is accessible when open', async ({ page }) => {
  await page.goto('/');
  await page.getByRole('button', { name: 'Open settings' }).click();

  const results = await new AxeBuilder({ page })
    .include('[role="dialog"]')
    .analyze();

  expect(results.violations).toEqual([]);
});$escape$,
