INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ce32e690-e517-4076-b8dc-10e709cfd171',
  '00000000-0000-0000-0000-000000000001',
  $escape$Playwright Test Data Management — Factories, Fixtures, and Seeding State$escape$,
  $escape$Hardcoding test data inline breeds brittle tests. Playwright's fixture system is the right hook for centralized test data management. Define a `userFactory` that generates deterministic or randomized user objects, then wire it into a custom `test` fixture that seeds your database via API calls in `beforeEach` and tears down in `afterEach` — all scoped per-test or per-worker.

Use `test.extend()` to compose fixtures: a `seededUser` fixture can depend on a `request` fixture to hit your `/api/test/seed` endpoint, returning a typed object your test consumes directly. Worker-scoped fixtures (`scope: 'worker'`) amortize expensive seeds — like a pre-authenticated session — across the full worker, while test-scoped fixtures isolate mutable state.

For UI-heavy flows, combine `page.goto()` with `storageState` snapshots: seed auth state once, serialize it with `context.storageState()`, then reuse it across tests via `use: { storageState: 'state.json' }` in `playwright.config.ts`. This eliminates redundant login flows while keeping state deterministic and isolated per test run.$escape$,
  $escape$import { test as base, request } from '@playwright/test';

type Fixtures = { seededUser: { id: string; email: string } };

export const test = base.extend<Fixtures>({
  seededUser: async ({ }, use) => {
    const ctx = await request.newContext();
    const res = await ctx.post('/api/test/seed', {
      data: { role: 'admin', email: `user-${Date.now()}@test.com` },
    });
    const user = await res.json();
    await use(user);
    await ctx.delete(`/api/test/seed/${user.id}`);
    await ctx.dispose();
  },
});

test('admin sees dashboard', async ({ page, seededUser }) => {
  await page.goto(`/dashboard?userId=${seededUser.id}`);
  await expect(page.getByRole('heading', { name: 'Admin Panel' })).toBeVisible();
});$escape$,
