INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '406eb96f-7d22-44b7-8dcd-b4ce9c737653',
  '00000000-0000-0000-0000-000000000001',
  $escape$Playwright Component Testing — Vite-Native Speed, Jest-Compatible Assertions, In-Source Test Files$escape$,
  $escape$Playwright's component testing (`@playwright/experimental-ct-react`) runs real browser interactions but is Vite-powered under the hood. Edit a component and the test re-runs via HMR without a full browser restart — same sub-second feedback loop you get with Vitest for unit tests. The `expect` API is intentionally Jest/Vitest-compatible: `await expect(component).toBeVisible()` and `await expect(component).toContainText('Submit')` mirror Vitest's chainable interface, so assertion muscle memory transfers directly. The key asymmetry: Playwright CT assertions are always async and locator-based, while Vitest assertions on DOM nodes are synchronous — mixing both in one repo means `await` discipline matters. Configure `testMatch` in `playwright-ct.config.ts` to `**/*.ct.spec.tsx` inside `src/`, placing component tests next to the source files they cover. This in-source layout is the same pattern Vitest encourages for unit tests. The result: Vitest handles pure logic co-located with source, Playwright CT handles interaction fidelity co-located with components — both sharing Vite's module graph and the same assertion vocabulary.$escape$,
  $escape$// playwright-ct.config.ts
import { defineConfig } from '@playwright/experimental-ct-react';

export default defineConfig({
  testDir: './src',
  testMatch: '**/*.ct.spec.tsx',
  use: {
    ctViteConfig: {
      plugins: [], // reuse existing vite.config.ts plugins here
    },
  },
});

// src/components/Button.ct.spec.tsx
import { test, expect } from '@playwright/experimental-ct-react';
import Button from './Button';

test('renders and responds to click', async ({ mount }) => {
  const component = await mount(<Button label="Submit" />);
  await expect(component).toContainText('Submit');
  await expect(component).toBeVisible();
  await component.click();
});$escape$,
