INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'df96166a-e6a6-4653-ac6c-68bce1d3b507',
  '00000000-0000-0000-0000-000000000001',
  $escape$Playwright's Trace Viewer + Network Interception: Debug Failures Like a Pro$escape$,
  $escape$When a Playwright test fails in CI, the trace viewer is your first stop — not console logs. Enable it via `use: { trace: 'on-first-retry' }` in `playwright.config.ts`, then open `npx playwright show-trace trace.zip` to replay every action, snapshot, and network request with a timeline scrubber.

Pair this with `page.route()` to intercept and mock network calls before they hit the wire. You can return fixture JSON for slow or flaky third-party APIs, simulate 500 errors to test error boundaries, or abort specific asset requests to speed up tests. Routes are matched by glob or regex against the full URL.

For multi-browser coverage, use the `projects` array in config to run the same spec against `chromium`, `firefox`, and `webkit` in parallel — each project can override `use` settings, so you can enable video recording only for WebKit. Run a single project with `--project=webkit` during local debugging to avoid full suite overhead. The trace viewer is browser-agnostic and works identically across all three engines.$escape$,
  $escape$import { test, expect } from '@playwright/test';

test('mocks API and captures trace on retry', async ({ page }) => {
  await page.route('**/api/feed', async route => {
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({ items: [{ id: 1, title: 'Mocked Byte' }] }),
    });
  });

  await page.goto('/feed');
  await expect(page.getByText('Mocked Byte')).toBeVisible();

  // Simulate upstream error for error-boundary test
  await page.route('**/api/feed', route => route.fulfill({ status: 500 }));
  await page.reload();
  await expect(page.getByRole('alert')).toBeVisible();
});$escape$,
