INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '957c3a91-529a-41da-9e8a-4086518af695',
  '00000000-0000-0000-0000-000000000001',
  $escape$Playwright page.route() — Intercepting, Mocking, and Overriding Network Requests$escape$,
  $escape$`page.route()` is Playwright's network interception primitive — register a glob or regex pattern and intercept every matching request before it hits the wire. Unlike Cypress's `cy.intercept`, `page.route()` is async by design: your handler receives a `Route` object and must settle it with exactly one of `route.fulfill()`, `route.abort()`, or `route.continue()`.

`route.fulfill()` returns arbitrary status codes, headers, and bodies — ideal for mocking REST or GraphQL endpoints without a running server. `route.abort()` simulates failure conditions (`failed`, `timedout`, `connectionreset`). `route.continue()` passes the request through, letting you selectively rewrite headers or the post body mid-flight.

When you need per-test overrides, register a second `page.route()` for the same pattern — Playwright resolves the most recently registered handler first, so you get clean, teardown-free overrides on top of a `beforeEach` baseline.

To assert on outgoing requests, capture them inside the handler via `route.request()` or pair with `page.waitForRequest()`. For deterministic fixture-driven tests, `page.routeFromHAR()` replays recorded sessions verbatim — no manual stub maintenance required.$escape$,
  $escape$import { test, expect } from '@playwright/test';

test.beforeEach(async ({ page }) => {
  await page.route('**/api/posts', (route) =>
    route.fulfill({ status: 200, json: [{ id: 1, title: 'Hello' }] })
  );
});

test('shows error state on 500', async ({ page }) => {
  // Most-recent handler wins — overrides the beforeEach stub
  await page.route('**/api/posts', (route) =>
    route.fulfill({ status: 500, json: { error: 'Server error' } })
  );

  await page.goto('/feed');
  await expect(page.getByRole('alert')).toContainText('Failed to load posts');
});$escape$,
