INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ab90b5a7-f6a1-46b3-a0ba-821d6dbb630e',
  '00000000-0000-0000-0000-000000000001',
  $escape$Playwright + Storybook — Your Stories Are Already Integration Tests$escape$,
  $escape$Storybook's test runner is powered by Playwright under the hood. When you define a `play` function in a story, Playwright navigates to that story's isolated iframe, executes the interaction sequence, and surfaces failures as proper test cases. Your documentation and your test suite are the same artifact.

The `.storybook/test-runner.ts` config exposes Playwright's `page` object directly through `preVisit` and `postVisit` hooks. This gives you the full Playwright API per story — `page.screenshot()` for visual regression baselines, `page.evaluate()` for DOM state inspection, or `axe-playwright` for a11y auditing across every component variant.

For CI: `storybook build && npx test-storybook --url http://localhost:6006`. Add `--shard 1/4` to parallelize since each story maps to an independent Playwright page visit.

One sharp edge: `userEvent` inside `play` functions uses `@testing-library/user-event` — not Playwright's native input engine. For precise pointer coordinates or drag sequences, reach for `page.mouse.move()` and `page.mouse.down()` inside `postVisit` instead.$escape$,
  $escape$// .storybook/test-runner.ts
import type { TestRunnerConfig } from '@storybook/test-runner';
import { checkA11y, injectAxe } from 'axe-playwright';

const config: TestRunnerConfig = {
  async preVisit(page) {
    await injectAxe(page);
  },
  async postVisit(page, context) {
    await checkA11y(page, '#storybook-root', {
      detailedReport: true,
      detailedReportOptions: { html: true },
    });
    await page.screenshot({ path: `screenshots/${context.id}.png` });
  },
};

export default config;$escape$,
  $escape$typescript$escape$,
