INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '08b2510b-495d-4e46-b52c-2f08be02af4e',
  '00000000-0000-0000-0000-000000000001',
  $escape$Playwright Code Coverage — What It Tells You and What It Doesn't$escape$,
  $escape$Playwright's `page.coverage` API (Chromium-only) tracks which JavaScript byte ranges executed during a test. It's useful for finding dead code. What it cannot do is tell you whether your assertions are meaningful.

A test that calls `page.goto('/checkout')` and clicks through a happy path can report 85% JS coverage while your error boundary, retry logic, and empty-state branches remain completely untested. Coverage measures execution, not assertion quality.

Three traps to avoid:

**Coverage ≠ confidence.** A test with zero `expect()` calls can hit 100% coverage. Playwright executes your app's JS; it doesn't evaluate whether the output was correct.

**Branch blindness.** V8 coverage reports byte ranges, not branch outcomes. An `if/else` where only the `if` arm ran looks identical to one where both ran — unless you convert via `v8-to-istanbul` and inspect Istanbul's branch map explicitly.

**Navigation resets.** `startJSCoverage()` resets counters on each navigation by default. Pass `{ resetOnNavigation: false }` to accumulate coverage across a multi-page flow, or you'll silently undercount.

Use coverage as a deletion metric: it reliably identifies untouched modules. It says nothing about whether the touched code was tested well.$escape$,
  $escape$import { test, expect } from '@playwright/test';

test('coverage that lies without assertions', async ({ page }) => {
  await page.coverage.startJSCoverage({ resetOnNavigation: false });

  await page.goto('/checkout');
  await page.getByRole('button', { name: 'Place Order' }).click();
  await page.waitForURL('/confirmation');

  const coverage = await page.coverage.stopJSCoverage();
  const executedBytes = coverage.reduce((sum, e) =>
    sum + e.ranges.reduce((s, r) => s + r.end - r.start, 0), 0);
  const totalBytes = coverage.reduce((sum, e) => sum + e.text.length, 0);
  console.log(`JS Coverage: ${((executedBytes / totalBytes) * 100).toFixed(1)}%`);

  // The number above is theater without this line:
  await expect(page.getByTestId('order-confirmation-id')).toBeVisible();
});$escape$,
